  "hero.exploreJourneys": "Explorează Călătoriile", "hero.browseStays": "Vezi Sejururile", "hero.exploreFlights": "Explorează Zborurile", "hero.browseFlights": "Vezi Zborurile", "hero.exploreStays": "Explorează Sejururile", "hero.exploreCruises": "Explorează Croazierele", "hero.exploreRailJourneys": "Explorează Călătoriile cu Trenul", "hero.exploreExperiences": "Explorează Experiențele", "hero.exploreBespokeJourneys": "Explorează Călătoriile Personalizate",
