  "flightSearch.roundTrip": "Dus-întors", "flightSearch.oneWay": "Doar dus", "flightSearch.multiCity": "Mai multe orașe", "flightSearch.removeFlight": "Elimină zborul", "flightSearch.addAnotherFlight": "Adaugă un Alt Zbor", "flightSearch.multiCityHint": "Echipa noastră de concierge vă va pregăti itinerarul cu mai multe orașe", "flightSearch.requestItinerary": "Solicită Itinerarul", "flightSearch.multiCityMessageIntro": "Aș dori să întreb despre un itinerar de zbor cu mai multe orașe:", "flightSearch.from": "De la", "flightSearch.to": "La",
