  "careers.role1": "Senior Rejsedesigner", "careers.role2": "Concierge-chef — Mellemøsten", "careers.role3": "Specialist i Privatfly", "careers.role4": "Leder af Hotelpartnerskaber", "careers.role5": "Kartograf for Skræddersyede Rejser", "careers.role6": "Medarbejder Gæsteoplevelse", "careers.role7": "Redaktør Indhold & Magasin", "careers.role8": "Specialist i Krydstogt & Tog", "careers.deptJourneyDesign": "Rejsedesign", "careers.deptGuestRelations": "Gæsterelationer", "careers.deptFlights": "Flyrejser", "careers.deptPartnerships": "Partnerskaber", "careers.deptBrand": "Brand", "careers.deptVoyages": "Rejser", "careers.typeFullTime": "Fuldtid", "careers.typeContract": "Kontrakt", "careers.typePartTime": "Deltid", "careers.locRemote": "Fjern", "careers.locRemoteIndia": "Fjern (Indien)", "careers.value1Title": "Besat Opmærksomhed", "careers.value1Body": "Vi går op i detaljer, som ingen gæst nogensinde vil bemærke — for dem, der bemærker dem, er netop dem, vi skaber det for.", "careers.value2Title": "Stille Selvsikkerhed", "careers.value2Body": "Ægte luksus bebuder sjældent sig selv. Vi arbejder i en rolig, præcis og helt udchillet tone.", "careers.value3Title": "Verdensomspændende Nysgerrighed", "careers.value3Body": "Hvert medlem af teamet er inderst inde først og fremmest en rejsende: rastløs, belæst og altid i gang med at planlægge den næste rejse.",
  "press.eyebrow": "Presse", "press.title": "Presse & Medier",
  "press.intro": "Til interviews, pressemateriale eller partnerskabshistorier vil vores kommunikationsteam med glæde hjælpe.",
  "press.asFeaturedIn": "Vi Har Været Omtalt I", "press.mediaEnquiries": "Medieforespørgsler",
  "press.mediaEnquiriesDesc": "Pressekits, grundlæggerinterviews og billeder i høj opløsning er tilgængelige efter anmodning.",
  "press.quote1": "Det sjældne rejseatelier, der behandler et rejseprogram som et litterært værk — hver overgang gennemtænkt, intet overladt til tilfældet.", "press.quote2": "Voyages & Co.s Bhutan-rundrejse er den mest gennemtænkt tilrettelagte spirituelle rejse, vi har foretaget i et årti med dækning af regionen.", "press.quote3": "Det, der adskiller dem, er ikke femstjernet adgang — det har alle i denne kategori. Det er den tilbageholdenhed, hvormed de bruger den.", "press.quote4": "En privatflyafdeling, der faktisk forstår forskellen mellem et let jetfly og en langdistanceflyvning — sjældnere, end den burde være.", "press.quote5": "Blandt den håndfuld skræddersyede operatører, vi ville betro et første besøg på Maldiverne — eller et første besøg hvor som helst.", "press.factLabel1": "Grundlagt", "press.factLabel2": "Hovedkvarter", "press.factLabel3": "Kuraterede destinationer", "press.factLabel4": "Gennemsnitlig forberedelsestid for et rejseprogram", "press.factValue3": "60+ lande", "press.factValue4": "6–10 uger",
  "partners.eyebrow": "Partnerskaber", "partners.title": "Bliv Partner med Voyages & Co.",
  "partners.intro": "Vi samarbejder med verdens fineste ejendomme og kuratorer for at skabe rejser, vores medlemmer aldrig vil glemme.",
  "partners.ctaTitle": "Lad os starte en samtale", "partners.ctaSubtitle": "Vi vil meget gerne høre fra dig.",
  "partners.ctaButton": "Kontakt Partnerskaber",
  "partners.type1Title": "Hoteller & Resorts", "partners.type1Desc": "Præsentér jeres ejendom for en kræsen klientel, der værdsætter det exceptionelle og booker uden tøven.", "partners.type1Benefit1": "Kurateret placering", "partners.type1Benefit2": "Dedikeret relationsansvarlig", "partners.type1Benefit3": "Kvalificerede gæster af høj værdi", "partners.type1Benefit4": "Program for foretrukne partnere", "partners.type1Cta": "Bliv partner", "partners.type2Title": "Villaer & Private Godser", "partners.type2Desc": "Præsentér jeres residens for medlemmer, der søger privatliv, plads og upåklagelig service.", "partners.type2Benefit1": "Diskret opslag", "partners.type2Benefit2": "Kun screenede gæster", "partners.type2Benefit3": "Concierge-koordinering", "partners.type2Benefit4": "Skræddersyede kommercielle vilkår", "partners.type2Cta": "Bliv partner", "partners.type3Title": "Oplevelseskuratorer", "partners.type3Desc": "Del jeres sjældne, enestående oplevelser med rejsende, der søger netop det.", "partners.type3Benefit1": "Fortællestøtte", "partners.type3Benefit2": "Problemfri koordinering", "partners.type3Benefit3": "Premium-positionering", "partners.type3Benefit4": "Langsigtet samarbejde", "partners.type3Cta": "Samarbejd",
  "help.eyebrow": "Hvordan Kan Vi Hjælpe?", "help.title": "Hjælpecenter", "help.subtitle": "Svar på spørgsmål, vores medlemmer ofte stiller", "help.lookingForCancellations": "Leder du efter vores afbestillingspolitik?",
  "help.faq.membership.category": "Medlemskab", "help.faq.membership.q1": "Hvordan bliver jeg medlem af Voyages & Co.?", "help.faq.membership.a1": "Medlemskab er efter ansøgning. Send en anmodning via 'Anmod om Invitation', og et medlem af vores team vil kontakte dig for at forstå dine rejsepræferencer, før en invitation udsendes.", "help.faq.membership.q2": "Er der et medlemskabsgebyr?", "help.faq.membership.a2": "Vi tilbyder lagdelte medlemskaber tilpasset din rejsestil. Din dedikerede specialist vil diskutere den bedste mulighed for dig under onboarding.", "help.faq.membership.q3": "Kan jeg rejse med gæster?", "help.faq.membership.a3": "Selvfølgelig. Dit medlemskab udvides til dine rejsefæller og nærmeste familie, med samme niveau af omsorg hele vejen.",
  "help.faq.journeys.category": "Rejser og Bookinger", "help.faq.journeys.q1": "Hvordan arrangeres rejser?", "help.faq.journeys.a1": "Hver rejse er håndlavet af din dedikerede specialist. Del dine datoer, interesser og præferencer, og vi designer en skræddersyet rejserute til din godkendelse — finpudset til perfektion.", "help.faq.journeys.q2": "Tager I hånd om alle elementer af rejsen?", "help.faq.journeys.a2": "Ja. Flyrejser, private transfers, ophold, gastronomi, oplevelser og support på stedet arrangeres og overvåges alle af din concierge.", "help.faq.journeys.q3": "Hvor langt i forvejen bør jeg planlægge?", "help.faq.journeys.a3": "For de mest eksklusive ophold og oplevelser anbefaler vi at planlægge flere måneder i forvejen. Vores netværk gør det dog muligt for os at arrangere bemærkelsesværdige rejser med kort varsel.",
  "help.faq.support.category": "Concierge og Support", "help.faq.support.q1": "Er der support tilgængelig, mens jeg rejser?", "help.faq.support.a1": "Altid. Din concierge er tilgængelig 24 timer i døgnet, i alle tidszoner, for alt, hvad du måtte have brug for under din rejse.", "help.faq.support.q2": "Hvad hvis mine planer ændrer sig?", "help.faq.support.a2": "Kontakt blot din specialist. Vi justerer diskret din rejserute og håndterer alle ordninger på dine vegne.", "help.faq.support.q3": "Hvordan beskyttes mit privatliv?", "help.faq.support.a3": "Discretion er fundamentalt for os. Dine oplysninger og rejseruter opbevares med den strengeste fortrolighed og deles aldrig.",
  "help.searchPlaceholder": "Søg efter hjælp…", "help.noResultsPrefix": "Ingen svar matcher", "help.noResultsSuffix": "— prøv kontaktmulighederne nedenfor.",
  "help.callUs": "Ring til Os", "help.callUsSub": "24/7 globalt", "help.whatsapp": "WhatsApp", "help.whatsappSub": "Skriv til os når som helst",
