  "cruisesPage.eyebrow": "Cruise Verden Over", "cruisesPage.title": "Seil Hvor Som Helst",
  "cruisesPage.intro": "Fra karibiske megaskip til intime Antarktis-ekspedisjoner og nilbåter — utvalgte reiser over hvert hav, sjø og elv på jorden.",
  "cruisesPage.style": "Stil", "cruisesPage.voyage": "cruise", "cruisesPage.voyages": "cruise", "cruisesPage.noMatch": "Ingen cruise matcher ditt valg.",
  "packagesPage.title": "Håndlagde Reiseruter",
  "packagesPage.intro": "All-inclusive-reiser med private transfere, utvalgte opphold og eksklusiv tilgang. Hver detalj arrangert av din dedikerte concierge.",
