  "help.faq.membership.category": "رکنیت", "help.faq.membership.q1": "میں Voyages & Co. کا رکن کیسے بن سکتا ہوں؟", "help.faq.membership.a1": "رکنیت درخواست کے ذریعے دی جاتی ہے۔ 'دعوت نامہ طلب کریں' کے ذریعے درخواست جمع کریں، اور ہماری ٹیم کا ایک رکن دعوت نامہ بھیجنے سے پہلے آپ کی سفری ترجیحات کو سمجھنے کے لیے آپ سے رابطہ کرے گا۔", "help.faq.membership.q2": "کیا رکنیت کی فیس ہے؟", "help.faq.membership.a2": "ہم آپ کے سفر کرنے کے انداز کے مطابق درجہ بندی شدہ رکنیتیں پیش کرتے ہیں۔ آپ کا مخصوص ماہر شمولیت کے دوران آپ کے لیے بہترین آپشن پر بات کرے گا۔", "help.faq.membership.q3": "کیا میں مہمانوں کے ساتھ سفر کر سکتا ہوں؟", "help.faq.membership.a3": "بالکل۔ آپ کی رکنیت آپ کے سفری ساتھیوں اور قریبی خاندان تک پھیلی ہوئی ہے، ہر وقت ایک ہی معیار کی دیکھ بھال کے ساتھ۔",
  "help.faq.journeys.category": "سفر اور بکنگ", "help.faq.journeys.q1": "سفر کیسے ترتیب دیے جاتے ہیں؟", "help.faq.journeys.a1": "ہر سفر آپ کے مخصوص ماہر کی طرف سے ہاتھ سے تیار کیا جاتا ہے۔ اپنی تاریخیں، دلچسپیاں اور ترجیحات شیئر کریں، اور ہم آپ کی منظوری کے لیے ایک خصوصی سفری منصوبہ تیار کریں گے — کمال تک نکھارا گیا۔", "help.faq.journeys.q2": "کیا آپ سفر کے ہر عنصر کا خیال رکھتے ہیں؟", "help.faq.journeys.a2": "جی ہاں۔ پروازیں، نجی ٹرانسفر، قیام گاہیں، کھانا، تجربات اور موقع پر معاونت سب آپ کے کونسیئرج کے ذریعے ترتیب دیے اور ان کی نگرانی کی جاتی ہے۔", "help.faq.journeys.q3": "مجھے کتنا پہلے سے منصوبہ بندی کرنی چاہیے؟", "help.faq.journeys.a3": "سب سے خصوصی قیام گاہوں اور تجربات کے لیے، ہم کئی ماہ پہلے سے منصوبہ بندی کی تجویز دیتے ہیں۔ تاہم، ہمارا نیٹ ورک ہمیں مختصر اطلاع پر بھی شاندار سفر ترتیب دینے کی اجازت دیتا ہے۔",
  "help.faq.support.category": "کونسیئرج اور معاونت", "help.faq.support.q1": "کیا میرے سفر کے دوران معاونت دستیاب ہے؟", "help.faq.support.a1": "ہمیشہ۔ آپ کا کونسیئرج دن کے 24 گھنٹے، ہر ٹائم زون میں، آپ کے سفر کے دوران کسی بھی چیز کے لیے قابل رسائی ہے۔", "help.faq.support.q2": "اگر میرے منصوبے بدل جائیں تو کیا ہوگا؟", "help.faq.support.a2": "صرف اپنے ماہر سے رابطہ کریں۔ ہم احتیاط سے آپ کے سفری منصوبے کو ایڈجسٹ کریں گے اور آپ کی طرف سے تمام انتظامات سنبھالیں گے۔", "help.faq.support.q3": "میری رازداری کیسے محفوظ ہے؟", "help.faq.support.a3": "احتیاط ہماری بنیادی خصوصیت ہے۔ آپ کی معلومات اور سفری منصوبے سخت ترین رازداری میں رکھے جاتے ہیں اور کبھی شیئر نہیں کیے جاتے۔",
  "help.searchPlaceholder": "مدد تلاش کریں…", "help.noResultsPrefix": "اس سے ملنے والا کوئی جواب نہیں ملا", "help.noResultsSuffix": "— نیچے دیے گئے رابطے کے اختیارات آزمائیں۔",
