  "reservation.begin": "शुरू करें", "reservation.planJourney": "अपनी यात्रा की योजना बनाएं",
  "packagesPreview.eyebrow": "अनुकूलित यात्राएं", "packagesPreview.headlinePre": "हस्तनिर्मित", "packagesPreview.headlineEm": "यात्रा कार्यक्रम",
