  "trust.promiseEyebrow": "Voyages & Co. का वादा", "trust.commitment": "आपके लिए हमारी प्रतिबद्धता",
  "trust.pillar1.title": "विशिष्ट चयन",
  "trust.pillar1.desc": "हर होटल, अनुभव और यात्रा को हमारी लक्ज़री यात्रा विशेषज्ञों की टीम द्वारा व्यक्तिगत रूप से सत्यापित किया जाता है। हम केवल उन संपत्तियों के साथ साझेदारी करते हैं जो हमारे सख्त मानकों को पूरा करती हैं।",
  "trust.pillar2.title": "उत्कृष्ट सेवा",
  "trust.pillar2.desc": "आपकी पहली पूछताछ से अंतिम प्रस्थान तक, एक समर्पित कंसीयज आपकी यात्रा के हर विवरण का ध्यान रखता है।",
  "trust.pillar3.title": "गोपनीयता और विवेक",
  "trust.pillar3.desc": "आपकी प्राथमिकताएं, यात्रा कार्यक्रम और व्यक्तिगत जानकारी सख्त गोपनीयता में रखी जाती हैं, और कभी बेची या साझा नहीं की जाती।",
  "trust.pillar4.title": "गारंटीकृत उत्कृष्टता",
  "trust.pillar4.desc": "यदि आपकी यात्रा का कोई भी हिस्सा आपकी अपेक्षाओं पर खरा नहीं उतरता, तो हम इसे सुधारते हैं। कोई शर्त नहीं। कोई अपवाद नहीं। हमारी प्रतिष्ठा इस पर निर्भर है।",
  "trust.ctaPre": "अपनी", "trust.ctaEm": "असाधारण", "trust.ctaSuffix": "यात्रा शुरू करने के लिए तैयार हैं?",
