  "flightSearch.roundTrip": "Pulang-pergi", "flightSearch.oneWay": "Sekali jalan", "flightSearch.multiCity": "Multi-kota", "flightSearch.removeFlight": "Hapus penerbangan", "flightSearch.addAnotherFlight": "Tambah Penerbangan Lain", "flightSearch.multiCityHint": "Concierge kami akan menyiapkan rencana perjalanan multi-kota Anda", "flightSearch.requestItinerary": "Minta Rencana Perjalanan", "flightSearch.multiCityMessageIntro": "Saya ingin menanyakan tentang rencana perjalanan penerbangan multi-kota:", "flightSearch.from": "Dari", "flightSearch.to": "Ke",
  "flightSearch.travellersClass": "Penumpang & Kelas", "flightSearch.anyAirline": "Maskapai apa saja",
  "flightSearch.searchFlights": "Cari Penerbangan", "flightSearch.selectOriginDestination": "Pilih asal dan tujuan",
