  "popularDest.eyebrow": "Mga Piling Pagtakas", "popularDest.headlinePre": "Saan Dadalhin ng Susunod Mong", "popularDest.headlineEm": "Paglalakbay",
  "popularDest.headlineSuffix": "ang Iyo?", "popularDest.viewAll": "Tingnan Ang Lahat ng Destinasyon",
  "sigExp.eyebrow": "Mga Eksklusibong Karanasan", "sigExp.heading": "Higit sa Karaniwan",
  "sigExp.subtext": "Tatlong haligi ng pambihirang paglalakbay, bawat isa ay piniling may katumpakan at pangangalaga na bumubuo sa Voyages & Co.",
  "sigExp.wellness.title": "Wellness at Pagbabagong-buhay",
  "sigExp.wellness.description": "Sumawsaw sa mga nagbabagong-anyong spa retreat, sanctuary ng yoga, at mga paglalakbay na nagpapagaling sa pinakamapayapang lugar sa mundo.",
  "sigExp.wellness.tag": "Wellness", "sigExp.wellness.cta": "Tuklasin ang mga Retreat",
  "sigExp.culture.title": "Pagsisid sa Kultura",
  "sigExp.culture.description": "Pribadong access sa mga lugar ng pamana, ateliers, at sinaunang tradisyon — mga karanasang hindi available sa karaniwang manlalakbay.",
  "sigExp.culture.tag": "Kultura", "sigExp.culture.cta": "Tuklasin ang Kultura",
  "sigExp.adventure.title": "Pribadong Mga Ekspedisyon",
  "sigExp.adventure.description": "Planuhin ang inyong adbentura — pribadong safari, Himalayan trek, paglalakbay sa Antarctica, at malalayong pagtakas na ganap na nakaayon sa inyo.",
  "sigExp.adventure.tag": "Adbentura", "sigExp.adventure.cta": "Planuhin ang Inyong Ekspedisyon",
  "reservation.begin": "Simulan", "reservation.planJourney": "Planuhin ang Inyong Paglalakbay",
  "packagesPreview.eyebrow": "Paglalakbay na Naaayon sa Inyo", "packagesPreview.headlinePre": "Mga Gawang-Kamay na", "packagesPreview.headlineEm": "Itineraryo",
  "packagesPreview.viewAll": "Tingnan ang Lahat ng Paglalakbay", "packagesPreview.fromPerPerson": "Mula sa, kada tao", "packagesPreview.enquire": "Magtanong",
  "trust.promiseEyebrow": "Ang Pangako ng Voyages & Co.", "trust.commitment": "Aming Pangako sa Inyo",
  "trust.pillar1.title": "Natatanging Pagpili",
  "trust.pillar1.desc": "Bawat hotel, karanasan, at paglalakbay ay personal na sinuri ng aming koponan ng mga espesyalista sa luxury travel. Nagtatrabaho lamang kami sa mga property na nakakatugon sa aming mahigpit na pamantayan.",
  "trust.pillar2.title": "Walang-kapintasang Serbisyo",
  "trust.pillar2.desc": "Mula sa inyong unang pagtatanong hanggang sa huling pag-alis, isang dedikadong concierge ang nangangalaga sa bawat detalye ng inyong paglalakbay.",
  "trust.pillar3.title": "Privacy at Discretion",
  "trust.pillar3.desc": "Ang inyong mga kagustuhan, itineraryo, at personal na impormasyon ay pinananatili sa istriktong pagkakumpidensyal, at hindi kailanman ibinebenta o ibinabahagi.",
  "trust.pillar4.title": "Garantisadong Kahusayan",
  "trust.pillar4.desc": "Kung ang anumang elemento ng inyong paglalakbay ay hindi nakatugon sa inyong inaasahan, itutuwid namin ito. Walang kondisyon. Walang eksepsyon. Ang aming reputasyon ay nakadepende dito.",
  "trust.ctaPre": "Handa na bang simulan ang inyong", "trust.ctaEm": "pambihirang", "trust.ctaSuffix": "paglalakbay?",
  "trust.ctaButton": "Kausapin ang Concierge",
