  "trips.eyebrow": "तुमचे खाते", "trips.title": "माझ्या सफरी", "trips.subtitle": "Voyages & Co. सोबत तुमची पुष्टी केलेली आरक्षणे",
  "trips.noReservations": "अद्याप आरक्षणे नाहीत", "trips.noReservationsDesc": "तुम्ही मुक्काम, विमान किंवा सफर पुष्टी केल्यावर, ती सुरक्षिततेसाठी इथे दिसेल.",
  "trips.browseStays": "मुक्काम पहा", "trips.findFlight": "विमान शोधा", "trips.browseCruises": "क्रूझ पहा", "trips.browseDestinations": "गंतव्ये पहा", "trips.browseExperiences": "अनुभव पहा", "trips.browseRailJourneys": "रेल्वे सफरी पहा", "trips.browseBespokeJourneys": "खास सफरी पहा", "trips.booked": "बुक केले", "trips.cancel": "रद्द करा",
